function s(e){if(!e)return"刚刚";const r=new Date(e);return Number.isNaN(r.getTime())?e:new Intl.DateTimeFormat("zh-CN",{month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit"}).format(r)}function u(e){if(!e)return"暂无";const r=new Date(e);return Number.isNaN(r.getTime())?e:new Intl.DateTimeFormat("zh-CN",{year:"numeric",month:"2-digit",day:"2-digit"}).format(r)}function c(e){if(!e)return"刚刚";const r=new Date(e),t=Date.now()-r.getTime();if(Number.isNaN(t))return e;const n=60*1e3,i=60*n,a=24*i;return t<n?"刚刚":t<i?`${Math.floor(t/n)} 分钟前`:t<a?`${Math.floor(t/i)} 小时前`:t<a*7?`${Math.floor(t/a)} 天前`:u(e)}function m(e){return e.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;")}function l(e){const r=e.trim();return r?r.replace(/\s+/g,"").slice(0,2).toUpperCase():"KP"}function d(e){const r=new Map;return e.forEach(t=>{t.tags.forEach(n=>{const i=n.trim();i&&r.set(i,(r.get(i)??0)+1)})}),[...r.entries()].map(([t,n])=>({label:t,count:n})).sort((t,n)=>n.count-t.count||t.label.localeCompare(n.label))}function f(e){return e.flatMap(r=>[r,...f(r.children)])}function o(e,r){for(const t of e){if(t.id===r)return t;const n=o(t.children,r);if(n)return n}return null}function g(e,r){var t;return((t=o(e,r))==null?void 0:t.name)??null}function p(e){const r=new Set;return e.split(/[，,]/).map(t=>t.trim()).filter(t=>!t||r.has(t)?!1:(r.add(t),!0))}export{u as a,f as b,g as c,o as d,m as e,s as f,d as g,l as i,p as n,c as r};
